--
-- Name: oficios; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.oficios (
    id integer NOT NULL,
    numero_folio integer,
    anio_folio smallint DEFAULT EXTRACT(year FROM now()) NOT NULL,
    folio_minutario character varying(30),
    folio_direccion character varying(100),
    dependencia_id integer,
    estado_id integer NOT NULL,
    tipo_documento_id integer,
    asunto text NOT NULL,
    descripcion text,
    observaciones text,
    fecha_recepcion date NOT NULL,
    fecha_oficio_tics date,
    fecha_acuse date,
    fecha_compromiso date,
    fecha_resolucion date,
    realizo character varying(120),
    usuario_capturo_id integer,
    usuario_responsable_id integer,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    tipo_oficio_id integer DEFAULT 1 NOT NULL,
    area_interna_id integer,
    folio_interno_texto character varying(100),
    folio_tesoreria character varying(60) GENERATED ALWAYS AS (
CASE
    WHEN (numero_folio IS NULL) THEN ('TM/ECA/STIyC/PENDIENTE/'::text || (anio_folio)::text)
    WHEN (numero_folio < 10000) THEN ((('TM/ECA/STIyC/'::text || lpad((numero_folio)::text, 4, '0'::text)) || '/'::text) || (anio_folio)::text)
    ELSE ((('TM/ECA/STIyC/'::text || (numero_folio)::text) || '/'::text) || (anio_folio)::text)
END) STORED,
    CONSTRAINT oficios_tipo_consistencia_chk CHECK ((((tipo_oficio_id = 1) AND (dependencia_id IS NOT NULL)) OR ((tipo_oficio_id = 2) AND (area_interna_id IS NOT NULL)) OR (tipo_oficio_id = 3)))
);


