--
-- Name: vw_import_oficios_conocimiento_errores; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_import_oficios_conocimiento_errores AS
 SELECT id AS staging_id,
    fuente,
    fila_excel,
    raw_fecha_recibido,
    raw_nombre_direccion,
    raw_folio_envia,
    raw_asunto,
    raw_status,
    estado_revision,
    accion,
    error_importacion,
    created_at
   FROM public.import_oficios_conocimiento_raw ic
  WHERE (((estado_revision)::text <> 'OK'::text) OR (error_importacion IS NOT NULL))
  ORDER BY fila_excel;


--
-- Name: vw_import_vacaciones_errores; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_import_vacaciones_errores AS
 SELECT id,
    source_file,
    source_sheet,
    fila_excel,
    numero_empleado_raw,
    nombre_raw,
    estado_revision,
    error_importacion,
    importado,
    created_at
   FROM public.import_vacaciones_sindicalizados_2026_raw
  WHERE (((estado_revision)::text <> 'OK'::text) OR (error_importacion IS NOT NULL));


--
-- Name: vw_importacion_errores; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_importacion_errores AS
 SELECT 'personal'::text AS origen,
    ip.id AS staging_id,
    ip.fuente,
    ip.fila_excel,
    ip.estado_revision,
    ip.error_importacion AS mensaje,
    ip.created_at
   FROM public.import_personal_raw ip
  WHERE (((ip.estado_revision)::text <> 'OK'::text) OR (ip.error_importacion IS NOT NULL))
UNION ALL
 SELECT 'vacaciones_sindicalizados_2026'::text AS origen,
    iv.id AS staging_id,
    (((iv.source_file)::text || '!'::text) || (iv.source_sheet)::text) AS fuente,
    iv.fila_excel,
    iv.estado_revision,
    iv.error_importacion AS mensaje,
    iv.created_at
   FROM public.import_vacaciones_sindicalizados_2026_raw iv
  WHERE (((iv.estado_revision)::text <> 'OK'::text) OR (iv.error_importacion IS NOT NULL))
UNION ALL
 SELECT 'folios_interno_sub'::text AS origen,
    fs.id AS staging_id,
    'BASE GENERAL.xlsx!FOLIOS INTERNO SUB'::character varying AS fuente,
    fs.fila_excel,
        CASE
            WHEN (fs.error_mensaje IS NULL) THEN 'OK'::text
            ELSE 'ERROR'::text
        END AS estado_revision,
    fs.error_mensaje AS mensaje,
    fs.created_at
   FROM public.import_folios_interno_sub_raw fs
  WHERE (fs.error_mensaje IS NOT NULL);


--
-- Name: vw_incidencias_por_personal; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_incidencias_por_personal AS
 SELECT i.personal_id,
    p.numero_empleado,
    p.nombre_completo,
    count(*) AS total,
    count(*) FILTER (WHERE ((ei.clave)::text = 'REGISTRADA'::text)) AS registradas,
    count(*) FILTER (WHERE ((ei.clave)::text = 'JUSTIFICADA'::text)) AS justificadas,
    count(*) FILTER (WHERE ((ei.clave)::text = 'NO_JUSTIFICADA'::text)) AS no_justificadas,
    count(*) FILTER (WHERE ((ei.clave)::text = 'CANCELADA'::text)) AS canceladas,
    count(*) FILTER (WHERE ((ei.clave)::text = 'PENDIENTE_REVISION'::text)) AS pendientes,
    count(*) FILTER (WHERE ((ti.clave)::text = 'FALTA'::text)) AS faltas,
    count(*) FILTER (WHERE ((ti.clave)::text = 'OMISION_ENTRADA'::text)) AS omision_entrada,
    count(*) FILTER (WHERE ((ti.clave)::text = 'OMISION_SALIDA'::text)) AS omision_salida,
    count(*) FILTER (WHERE ((ti.clave)::text = 'RETARDO'::text)) AS retardos,
    count(*) FILTER (WHERE ((ti.clave)::text = 'COMISION'::text)) AS comisiones,
    max(i.fecha_incidencia) AS ultima_fecha
   FROM (((public.incidencias i
     JOIN public.personal p ON ((p.id = i.personal_id)))
     JOIN public.tipos_incidencia ti ON ((ti.id = i.tipo_incidencia_id)))
     JOIN public.estatus_incidencia ei ON ((ei.id = i.estatus_id)))
  GROUP BY i.personal_id, p.numero_empleado, p.nombre_completo;


--
-- Name: vw_incidencias_por_tipo; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_incidencias_por_tipo AS
 SELECT ti.id AS tipo_id,
    ti.clave,
    ti.nombre,
    ti.color,
    ti.icono,
    count(i.id) AS total,
    count(i.id) FILTER (WHERE (i.fecha_incidencia >= (CURRENT_DATE - '30 days'::interval))) AS ultimos_30d,
    count(i.id) FILTER (WHERE (date_trunc('month'::text, (i.fecha_incidencia)::timestamp with time zone) = date_trunc('month'::text, (CURRENT_DATE)::timestamp with time zone))) AS mes_actual
   FROM (public.tipos_incidencia ti
     LEFT JOIN public.incidencias i ON ((i.tipo_incidencia_id = ti.id)))
  WHERE (ti.activo = true)
  GROUP BY ti.id, ti.clave, ti.nombre, ti.color, ti.icono, ti.orden
  ORDER BY ti.orden;


--
-- Name: vw_incidencias_resumen; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_incidencias_resumen AS
 SELECT i.id,
    i.personal_id,
    p.numero_empleado,
    p.nombre_completo,
    tp.clave AS tipo_personal_clave,
    tp.nombre AS tipo_personal_nombre,
    ti.id AS tipo_incidencia_id,
    ti.clave AS tipo_clave,
    ti.nombre AS tipo_nombre,
    ti.color AS tipo_color,
    ti.icono AS tipo_icono,
    ei.id AS estatus_id,
    ei.clave AS estatus_clave,
    ei.nombre AS estatus_nombre,
    ei.color_bs AS estatus_color,
    i.fecha_incidencia,
    i.fecha_inicio,
    i.fecha_fin,
    i.fecha_recibido_coord,
    i.periodo,
    i.anio,
    i.mes,
    i.quincena,
    i.dias,
    i.horas,
    i.minutos,
    i.motivo,
    i.observaciones,
    i.justificacion,
    i.folio_justificacion,
    i.fuente,
    u.nombre AS capturo_nombre,
    i.capturado_por_user_id,
    i.created_at,
    i.updated_at
   FROM (((((public.incidencias i
     JOIN public.personal p ON ((p.id = i.personal_id)))
     JOIN public.tipos_personal tp ON ((tp.id = p.tipo_personal_id)))
     JOIN public.tipos_incidencia ti ON ((ti.id = i.tipo_incidencia_id)))
     JOIN public.estatus_incidencia ei ON ((ei.id = i.estatus_id)))
     LEFT JOIN public.usuarios u ON ((u.id = i.capturado_por_user_id)));


--
-- Name: vw_oficios_conocimiento; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_oficios_conocimiento AS
 SELECT o.id,
    o.folio_tesoreria,
    o.folio_direccion,
    o.asunto,
    o.observaciones,
    o.fecha_recepcion,
    o.fecha_acuse,
    o.created_at,
    o.updated_at,
    t.clave AS tipo_clave,
    t.nombre AS tipo_nombre,
    d.id AS dependencia_id,
    d.nombre AS dependencia_nombre,
    d.clave AS dependencia_clave,
    e.id AS estado_id,
    e.nombre AS estado_nombre,
    e.color AS estado_color,
    uc.nombre AS capturo_nombre
   FROM ((((public.oficios o
     JOIN public.tipos_oficio t ON ((t.id = o.tipo_oficio_id)))
     LEFT JOIN public.dependencias d ON ((d.id = o.dependencia_id)))
     LEFT JOIN public.estados_oficio e ON ((e.id = o.estado_id)))
     LEFT JOIN public.usuarios uc ON ((uc.id = o.usuario_capturo_id)))
  WHERE ((t.clave)::text = 'CONOCIMIENTO'::text);


--
-- Name: vw_oficios_por_tipo; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_oficios_por_tipo AS
 SELECT t.id AS tipo_id,
    t.clave AS tipo_clave,
    t.nombre AS tipo_nombre,
    t.requiere_respuesta,
    t.requiere_pdf_contestado,
    count(o.id) AS total,
    count(o.id) FILTER (WHERE ((e.nombre)::text = 'Archivado'::text)) AS archivados,
    count(o.id) FILTER (WHERE ((e.nombre)::text = 'De Conocimiento'::text)) AS de_conocimiento,
    count(o.id) FILTER (WHERE ((e.nombre)::text = 'Contestado'::text)) AS contestados,
    count(o.id) FILTER (WHERE ((t.requiere_respuesta = true) AND ((e.nombre)::text <> ALL ((ARRAY['Contestado'::character varying, 'Archivado'::character varying, 'De Conocimiento'::character varying])::text[])))) AS pendientes_por_responder
   FROM ((public.tipos_oficio t
     LEFT JOIN public.oficios o ON ((o.tipo_oficio_id = t.id)))
     LEFT JOIN public.estados_oficio e ON ((e.id = o.estado_id)))
  WHERE (t.activo = true)
  GROUP BY t.id, t.clave, t.nombre, t.requiere_respuesta, t.requiere_pdf_contestado
  ORDER BY t.clave;


--
-- Name: vw_personal_resumen; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_personal_resumen AS
 SELECT p.id,
    p.numero_empleado,
    p.nombre_completo,
    tp.clave AS tipo_clave,
    tp.nombre AS tipo_nombre,
    p.categoria,
    p.horario,
    p.activo,
    p.usuario_id,
    u.username AS usuario_username,
    p.created_at,
    p.updated_at
   FROM ((public.personal p
     JOIN public.tipos_personal tp ON ((tp.id = p.tipo_personal_id)))
     LEFT JOIN public.usuarios u ON ((u.id = p.usuario_id)));


--
-- Name: vw_vacaciones_movimientos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_vacaciones_movimientos AS
 SELECT m.id,
    m.personal_id,
    p.numero_empleado,
    p.nombre_completo,
    tp.clave AS tipo_personal_clave,
    tp.nombre AS tipo_personal_nombre,
    m.periodo_id,
    vp.clave AS periodo_clave,
    vp.nombre AS periodo_nombre,
    vp.anio AS periodo_anio,
    m.fecha_vacaciones,
    m.fecha_inicio,
    m.fecha_fin,
    m.fecha_regreso,
    m.fecha_recibido_coord,
    m.dias_corresponden,
    m.dias_tomados,
    m.dias_pendientes_excel,
    m.folio_tm_vacaciones,
    ev.clave AS estatus_clave,
    ev.nombre AS estatus_nombre,
    ev.color AS estatus_color,
    m.observaciones,
    u.nombre AS capturo_nombre,
    m.origen,
    m.created_at,
    m.updated_at,
        CASE
            WHEN ((ev.clave)::text = ANY ((ARRAY['CANCELADA'::character varying, 'PENDIENTE_REVISION'::character varying])::text[])) THEN ev.clave
            WHEN ((m.fecha_inicio IS NULL) OR (m.fecha_fin IS NULL)) THEN 'PROGRAMADA'::character varying
            WHEN (m.fecha_inicio > CURRENT_DATE) THEN 'PROGRAMADA'::character varying
            WHEN ((m.fecha_inicio <= CURRENT_DATE) AND (m.fecha_fin >= CURRENT_DATE)) THEN 'ACTIVA'::character varying
            ELSE 'FINALIZADA'::character varying
        END AS estatus_derivado
   FROM (((((public.vacaciones_movimientos m
     JOIN public.personal p ON ((p.id = m.personal_id)))
     JOIN public.tipos_personal tp ON ((tp.id = p.tipo_personal_id)))
     JOIN public.vacaciones_periodos vp ON ((vp.id = m.periodo_id)))
     JOIN public.estatus_vacaciones ev ON ((ev.id = m.estatus_id)))
     LEFT JOIN public.usuarios u ON ((u.id = m.capturado_por_user_id)));


--
-- Name: vw_vacaciones_pendientes_revision; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_vacaciones_pendientes_revision AS
 SELECT id,
    personal_id,
    numero_empleado,
    nombre_completo,
    tipo_personal_clave,
    tipo_personal_nombre,
    periodo_id,
    periodo_clave,
    periodo_nombre,
    periodo_anio,
    fecha_vacaciones,
    fecha_inicio,
    fecha_fin,
    fecha_regreso,
    fecha_recibido_coord,
    dias_corresponden,
    dias_tomados,
    dias_pendientes_excel,
    folio_tm_vacaciones,
    estatus_clave,
    estatus_nombre,
    estatus_color,
    observaciones,
    capturo_nombre,
    origen,
    created_at,
    updated_at,
    estatus_derivado
   FROM public.vw_vacaciones_movimientos vm
  WHERE ((estatus_clave)::text = 'PENDIENTE_REVISION'::text);


--
-- Name: vw_vacaciones_saldos_negativos; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_vacaciones_saldos_negativos AS
 SELECT vs.id,
    vs.personal_id,
    p.numero_empleado,
    p.nombre_completo,
    vp.clave AS periodo_clave,
    vp.nombre AS periodo_nombre,
    vp.anio,
    vs.dias_asignados,
    vs.dias_usados,
    vs.dias_restantes,
    vs.tiene_inconsistencia,
    vs.observaciones
   FROM ((public.vacaciones_saldos vs
     JOIN public.personal p ON ((p.id = vs.personal_id)))
     JOIN public.vacaciones_periodos vp ON ((vp.id = vs.periodo_id)))
  WHERE (vs.dias_restantes < 0);


--
-- Name: vw_vacaciones_sindicalizados_2026; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.vw_vacaciones_sindicalizados_2026 AS
 WITH base AS (
         SELECT p.id AS personal_id,
            p.numero_empleado,
            p.nombre_completo,
            tp.clave AS tipo_personal_clave,
            tp.nombre AS tipo_personal_nombre
           FROM (public.personal p
             JOIN public.tipos_personal tp ON ((tp.id = p.tipo_personal_id)))
          WHERE (p.activo = true)
        ), p1 AS (
         SELECT vs.personal_id,
            vs.dias_asignados,
            vs.dias_usados,
            vs.dias_restantes,
            vs.tiene_inconsistencia,
            vs.observaciones
           FROM (public.vacaciones_saldos vs
             JOIN public.vacaciones_periodos vp ON ((vp.id = vs.periodo_id)))
          WHERE ((vp.clave)::text = '1ER_PERIODO_2025'::text)
        ), p2 AS (
         SELECT vs.personal_id,
            vs.dias_asignados,
            vs.dias_usados,
            vs.dias_restantes,
            vs.tiene_inconsistencia,
            vs.observaciones
           FROM (public.vacaciones_saldos vs
             JOIN public.vacaciones_periodos vp ON ((vp.id = vs.periodo_id)))
          WHERE ((vp.clave)::text = '2DO_PERIODO_2025'::text)
        )
 SELECT b.personal_id,
    b.numero_empleado,
    b.nombre_completo,
    b.tipo_personal_clave,
    b.tipo_personal_nombre,
    COALESCE((p1.dias_asignados)::integer, 0) AS p1_asignados,
    COALESCE((p1.dias_usados)::integer, 0) AS p1_usados,
    COALESCE((p1.dias_restantes)::integer, 0) AS p1_restantes,
    COALESCE(p1.tiene_inconsistencia, false) AS p1_inconsistencia,
    p1.observaciones AS p1_observaciones,
    COALESCE((p2.dias_asignados)::integer, 0) AS p2_asignados,
    COALESCE((p2.dias_usados)::integer, 0) AS p2_usados,
    COALESCE((p2.dias_restantes)::integer, 0) AS p2_restantes,
    COALESCE(p2.tiene_inconsistencia, false) AS p2_inconsistencia,
    p2.observaciones AS p2_observaciones,
    (COALESCE(p1.tiene_inconsistencia, false) OR COALESCE(p2.tiene_inconsistencia, false)) AS tiene_inconsistencia_global
   FROM ((base b
     LEFT JOIN p1 ON ((p1.personal_id = b.personal_id)))
     LEFT JOIN p2 ON ((p2.personal_id = b.personal_id)))
  WHERE ((p1.personal_id IS NOT NULL) OR (p2.personal_id IS NOT NULL));


